import { useState, useEffect } from 'react';
import styled from 'styled-components';
import { 
  Menu, X, Plus, Image, Camera, FileText, Send, 
  MessageSquare, Trash2 
} from '@mui/icons-material';
import axios from 'axios';
import CodeBlock from './components/CodeBlock';
import GeometryViewer from './components/GeometryViewer';

const API_BASE_URL = 'http://localhost:5000/api';

const AppContainer = styled.div`
  display: flex;
  height: 100vh;
  background-color: #1a1a2e;
  color: #ffffff;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
`;

const Sidebar = styled.div`
  width: ${props => props.collapsed ? '60px' : '280px'};
  background-color: #16213e;
  border-right: 1px solid #2a2a4a;
  display: flex;
  flex-direction: column;
  transition: width 0.3s ease;
`;

const SidebarHeader = styled.div`
  padding: 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid #2a2a4a;
`;

const SidebarTitle = styled.h1`
  font-size: 18px;
  font-weight: 600;
  margin: 0;
  display: ${props => props.collapsed ? 'none' : 'block'};
`;

const NewChatButton = styled.button`
  width: ${props => props.collapsed ? '40px' : '100%'};
  height: 40px;
  border: none;
  border-radius: 8px;
  background-color: #0f3460;
  color: #ffffff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  margin-top: 16px;
  margin-left: 16px;
  margin-right: 16px;
  transition: background-color 0.2s;

  &:hover {
    background-color: #1a4d8c;
  }
`;

const ConversationList = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 8px;
`;

const ConversationItem = styled.div`
  padding: 12px;
  border-radius: 8px;
  cursor: pointer;
  margin-bottom: 4px;
  display: ${props => props.collapsed ? 'flex' : 'block'};
  align-items: center;
  justify-content: center;

  &:hover {
    background-color: #2a2a4a;
  }

  &.active {
    background-color: #0f3460;
  }
`;

const ConversationTitle = styled.div`
  font-size: 14px;
  font-weight: 500;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  display: ${props => props.collapsed ? 'none' : 'block'};
`;

const ConversationDate = styled.div`
  font-size: 12px;
  color: #888888;
  margin-top: 4px;
  display: ${props => props.collapsed ? 'none' : 'block'};
`;

const MainContent = styled.div`
  flex: 1;
  display: flex;
  flex-direction: column;
  position: relative;
`;

const ChatHeader = styled.div`
  padding: 16px 24px;
  background-color: #16213e;
  border-bottom: 1px solid #2a2a4a;
  display: flex;
  align-items: center;
  justify-content: space-between;
`;

const ChatTitle = styled.h2`
  font-size: 16px;
  font-weight: 600;
  margin: 0;
`;

const ChatActions = styled.div`
  display: flex;
  gap: 12px;
`;

const ChatActionButton = styled.button`
  background: none;
  border: none;
  color: #888888;
  cursor: pointer;
  padding: 8px;
  border-radius: 8px;
  transition: background-color 0.2s;

  &:hover {
    background-color: #2a2a4a;
    color: #ffffff;
  }
`;

const ChatMessages = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 24px;
`;

const MessageBubble = styled.div`
  max-width: 70%;
  margin-bottom: 16px;
  padding: 12px 16px;
  border-radius: 12px;

  &.user {
    margin-left: auto;
    background-color: #0f3460;
    border-bottom-right-radius: 4px;
  }

  &.assistant {
    margin-right: auto;
    background-color: #2a2a4a;
    border-bottom-left-radius: 4px;
  }
`;

const MessageContent = styled.div`
  font-size: 14px;
  line-height: 1.6;
`;

const MessageImage = styled.img`
  max-width: 100%;
  border-radius: 8px;
  margin-top: 8px;
`;

const MessageTimestamp = styled.div`
  font-size: 11px;
  color: #888888;
  margin-top: 8px;
  text-align: right;
`;

const TextSegment = styled.p`
  margin: 0 0 8px 0;
  &:last-child {
    margin-bottom: 0;
  }
`;

const InputArea = styled.div`
  padding: 16px 24px;
  background-color: #16213e;
  border-top: 1px solid #2a2a4a;
`;

const InputContainer = styled.div`
  background-color: #2a2a4a;
  border-radius: 12px;
  padding: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
`;

const InputTools = styled.div`
  display: flex;
  gap: 8px;
`;

const ToolButton = styled.button`
  background: none;
  border: none;
  color: #888888;
  cursor: pointer;
  padding: 8px;
  border-radius: 8px;
  transition: color 0.2s;

  &:hover {
    color: #ffffff;
  }
`;

const TextInput = styled.textarea`
  flex: 1;
  background: none;
  border: none;
  color: #ffffff;
  font-size: 14px;
  resize: none;
  outline: none;
  padding: 8px;
  min-height: 24px;
  max-height: 200px;
  overflow-y: auto;

  &::placeholder {
    color: #666666;
  }
`;

const SendButton = styled.button`
  background-color: #0f3460;
  border: none;
  color: #ffffff;
  cursor: pointer;
  padding: 8px 16px;
  border-radius: 8px;
  transition: background-color 0.2s;

  &:hover {
    background-color: #1a4d8c;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
`;

const EmptyState = styled.div`
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  text-align: center;
`;

const EmptyIcon = styled(MessageSquare)`
  font-size: 64px;
  color: #3a3a5a;
  margin-bottom: 16px;
`;

const EmptyTitle = styled.h3`
  font-size: 20px;
  font-weight: 600;
  margin: 0 0 8px 0;
`;

const EmptyDescription = styled.p`
  font-size: 14px;
  color: #888888;
  margin: 0;
`;

const LoadingIndicator = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 16px;
  background-color: #2a2a4a;
  border-radius: 12px;
  margin-right: auto;
  max-width: 70%;
`;

const LoadingDots = styled.div`
  display: flex;
  gap: 4px;
`;

const LoadingDot = styled.span`
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background-color: #0f3460;
  animation: loading 1.4s infinite ease-in-out both;

  &:nth-child(1) { animation-delay: -0.32s; }
  &:nth-child(2) { animation-delay: -0.16s; }
  &:nth-child(3) { animation-delay: 0s; }

  @keyframes loading {
    0%, 80%, 100% { transform: scale(0); }
    40% { transform: scale(1); }
  }
`;

function App() {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [conversations, setConversations] = useState([]);
  const [currentConversation, setCurrentConversation] = useState(null);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);

  useEffect(() => {
    fetchConversations();
  }, []);

  const fetchConversations = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/conversations`);
      setConversations(response.data);
    } catch (error) {
      console.error('Failed to fetch conversations:', error);
    }
  };

  const fetchConversation = async (conversationId) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/conversations/${conversationId}`);
      setCurrentConversation(response.data);
    } catch (error) {
      console.error('Failed to fetch conversation:', error);
    }
  };

  const createNewConversation = async () => {
    try {
      const response = await axios.post(`${API_BASE_URL}/conversations`);
      setCurrentConversation(response.data);
      fetchConversations();
    } catch (error) {
      console.error('Failed to create conversation:', error);
    }
  };

  const deleteConversation = async (conversationId) => {
    try {
      await axios.delete(`${API_BASE_URL}/conversations/${conversationId}`);
      if (currentConversation && currentConversation._id === conversationId) {
        setCurrentConversation(null);
      }
      fetchConversations();
    } catch (error) {
      console.error('Failed to delete conversation:', error);
    }
  };

  const handleSendMessage = async () => {
    if (!inputValue.trim() && !selectedFile) return;

    setIsLoading(true);

    try {
      let imageBase64 = null;
      if (selectedFile) {
        const reader = new FileReader();
        imageBase64 = await new Promise((resolve) => {
          reader.onload = (e) => resolve(e.target.result.split(',')[1]);
          reader.readAsDataURL(selectedFile);
        });
      }

      const response = await axios.post(
        `${API_BASE_URL}/conversations/${currentConversation._id}/message`,
        {
          content: inputValue,
          imageBase64: imageBase64
        }
      );

      setCurrentConversation(response.data.conversation);
      setInputValue('');
      setSelectedFile(null);
      fetchConversations();
    } catch (error) {
      console.error('Failed to send message:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSelect = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith('image/')) {
      setSelectedFile(file);
    }
  };

  const handleCameraCapture = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.capture = 'environment';
    input.onchange = (e) => {
      const file = e.target.files[0];
      if (file) {
        setSelectedFile(file);
      }
    };
    input.click();
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      setSelectedFile(file);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('zh-CN', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const parseMessageContent = (content) => {
    const parts = [];
    const geometryMatch = content.match(/\[GEOMETRY:(.*?)\]/);
    const codeMatch = content.match(/```python\n([\s\S]*?)```/);

    let remainingContent = content;

    if (geometryMatch) {
      try {
        const geometryInfo = JSON.parse(geometryMatch[1]);
        parts.push({ type: 'geometry', data: geometryInfo });
        remainingContent = remainingContent.replace(geometryMatch[0], '');
      } catch (e) {
        console.error('Failed to parse geometry info:', e);
      }
    }

    if (codeMatch) {
      parts.push({ type: 'code', data: codeMatch[1].trim() });
      remainingContent = remainingContent.replace(codeMatch[0], '');
    }

    if (remainingContent.trim()) {
      parts.push({ type: 'text', data: remainingContent.trim() });
    }

    return parts;
  };

  const renderMessageContent = (content) => {
    const parts = parseMessageContent(content);

    return parts.map((part, index) => {
      switch (part.type) {
        case 'geometry':
          return <GeometryViewer key={`geo-${index}`} shapeInfo={part.data} />;
        case 'code':
          return <CodeBlock key={`code-${index}`} code={part.data} />;
        case 'text':
          return <TextSegment key={`text-${index}`}>{part.data}</TextSegment>;
        default:
          return null;
      }
    });
  };

  return (
    <AppContainer>
      <Sidebar collapsed={sidebarCollapsed}>
        <SidebarHeader>
          <SidebarTitle collapsed={sidebarCollapsed}>DeepSeek Chat</SidebarTitle>
          <button
            onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
            style={{
              background: 'none',
              border: 'none',
              color: '#ffffff',
              cursor: 'pointer',
              padding: '8px'
            }}
          >
            {sidebarCollapsed ? <Menu /> : <X />}
          </button>
        </SidebarHeader>

        <NewChatButton collapsed={sidebarCollapsed} onClick={createNewConversation}>
          <Plus />
          {!sidebarCollapsed && '新对话'}
        </NewChatButton>

        <ConversationList>
          {conversations.length === 0 ? (
            !sidebarCollapsed && (
              <div style={{ padding: '16px', textAlign: 'center', color: '#666666' }}>
                暂无对话
              </div>
            )
          ) : (
            conversations.map((conv) => (
              <ConversationItem
                key={conv._id}
                collapsed={sidebarCollapsed}
                className={currentConversation?._id === conv._id ? 'active' : ''}
                onClick={() => fetchConversation(conv._id)}
                onContextMenu={(e) => {
                  e.preventDefault();
                  if (confirm('确定删除此对话？')) {
                    deleteConversation(conv._id);
                  }
                }}
              >
                {sidebarCollapsed ? (
                  <MessageSquare style={{ fontSize: '20px' }} />
                ) : (
                  <>
                    <ConversationTitle collapsed={sidebarCollapsed}>
                      {conv.title}
                    </ConversationTitle>
                    <ConversationDate collapsed={sidebarCollapsed}>
                      {formatDate(conv.updatedAt)}
                    </ConversationDate>
                  </>
                )}
              </ConversationItem>
            ))
          )}
        </ConversationList>
      </Sidebar>

      <MainContent>
        {currentConversation ? (
          <>
            <ChatHeader>
              <ChatTitle>{currentConversation.title}</ChatTitle>
              <ChatActions>
                <ChatActionButton onClick={createNewConversation} title="新对话">
                  <Plus />
                </ChatActionButton>
                <ChatActionButton
                  onClick={() => {
                    if (confirm('确定删除此对话？')) {
                      deleteConversation(currentConversation._id);
                    }
                  }}
                  title="删除对话"
                >
                  <Trash2 />
                </ChatActionButton>
              </ChatActions>
            </ChatHeader>

            <ChatMessages>
              {currentConversation.messages.map((message, index) => (
                <MessageBubble key={index} className={message.role}>
                  <MessageContent>
                    {renderMessageContent(message.content)}
                  </MessageContent>
                  {message.imageUrl && (
                    <MessageImage src={message.imageUrl} alt="图片" />
                  )}
                  <MessageTimestamp>
                    {formatDate(message.timestamp)}
                  </MessageTimestamp>
                </MessageBubble>
              ))}
              {isLoading && (
                <LoadingIndicator>
                  <LoadingDots>
                    <LoadingDot />
                    <LoadingDot />
                    <LoadingDot />
                  </LoadingDots>
                  <span style={{ fontSize: '14px' }}>思考中...</span>
                </LoadingIndicator>
              )}
            </ChatMessages>

            <InputArea>
              <InputContainer>
                <InputTools>
                  <ToolButton>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleImageSelect}
                      style={{ display: 'none' }}
                      id="image-upload"
                    />
                    <label htmlFor="image-upload" style={{ cursor: 'pointer' }}>
                      <Image />
                    </label>
                  </ToolButton>
                  <ToolButton onClick={handleCameraCapture}>
                    <Camera />
                  </ToolButton>
                  <ToolButton>
                    <input
                      type="file"
                      onChange={handleFileSelect}
                      style={{ display: 'none' }}
                      id="file-upload"
                    />
                    <label htmlFor="file-upload" style={{ cursor: 'pointer' }}>
                      <FileText />
                    </label>
                  </ToolButton>
                </InputTools>
                <TextInput
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder="输入问题..."
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendMessage();
                    }
                  }}
                />
                <SendButton onClick={handleSendMessage} disabled={!inputValue.trim() && !selectedFile}>
                  <Send />
                </SendButton>
              </InputContainer>
              {selectedFile && (
                <div style={{ marginTop: '8px', color: '#888888', fontSize: '12px' }}>
                  已选择文件: {selectedFile.name}
                </div>
              )}
            </InputArea>
          </>
        ) : (
          <EmptyState>
            <EmptyIcon />
            <EmptyTitle>开始新对话</EmptyTitle>
            <EmptyDescription>
              点击左侧按钮创建新对话，开始与AI交流
            </EmptyDescription>
          </EmptyState>
        )}
      </MainContent>
    </AppContainer>
  );
}

export default App;
